"use client";

import React from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Check, Sparkles, ArrowRight, Crown, Star } from "lucide-react";

interface PricingCardProps {
  title: string;
  price: string;
  features: string[];
  highlighted?: boolean;
  className?: string;
}

const PricingCard: React.FC<PricingCardProps> = ({
  title,
  price,
  features,
  highlighted = false,
  className = ""
}) => {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      whileHover={{ 
        y: -8,
        scale: 1.02,
        transition: { duration: 0.3, ease: "easeOut" }
      }}
      className={`relative ${className}`}
    >
      {/* Animated border gradient */}
      <div className={`absolute inset-0 rounded-3xl bg-gradient-to-r ${
        highlighted 
          ? "from-purple-600 via-pink-600 to-indigo-600 opacity-100" 
          : "from-blue-500 via-purple-500 to-pink-500 opacity-0"
      } transition-opacity duration-500 group-hover:opacity-100`} />

      {/* Main card container */}
      <div className={`relative backdrop-blur-xl rounded-3xl border-2 ${
        highlighted 
          ? "bg-gradient-to-br from-slate-900/95 to-slate-800/95 border-purple-500/50 shadow-2xl shadow-purple-500/25" 
          : "bg-white/95 border-slate-200/50 shadow-xl"
      } p-8 transition-all duration-500`}>

        {/* Popular badge */}
        <AnimatePresence>
          {highlighted && (
            <motion.div
              initial={{ opacity: 0, scale: 0.5 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.5 }}
              className="absolute -top-6 left-1/2 transform -translate-x-1/2 z-20"
            >
              <motion.div
                animate={{ 
                  rotate: [0, 5, -5, 0],
                  scale: [1, 1.05, 1]
                }}
                transition={{ 
                  duration: 2, 
                  repeat: Infinity, 
                  ease: "easeInOut" 
                }}
                className="bg-gradient-to-r from-amber-400 via-orange-500 to-red-500 text-white text-xs font-bold px-6 py-2.5 rounded-full shadow-2xl flex items-center gap-2"
              >
                <Crown className="w-4 h-4" />
                <span>POPULAR</span>
                <Sparkles className="w-3 h-3" />
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Header section */}
        <div className="text-center mb-8">
          <motion.h3 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.1 }}
            className={`text-3xl font-black mb-4 ${
              highlighted ? "text-white" : "text-slate-900"
            }`}
          >
            {title}
          </motion.h3>

          <motion.div 
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.2 }}
            className="flex items-baseline justify-center gap-2"
          >
            <span className={`text-6xl font-black ${
              highlighted ? "text-white" : "text-slate-900"
            }`}>{price}</span>
            <span className={`text-lg font-medium ${
              highlighted ? "text-white/70" : "text-slate-600"
            }`}>/month</span>
          </motion.div>
        </div>

        {/* Features list */}
        <div className={`space-y-4 mb-8 ${
          highlighted ? "text-white" : "text-slate-700"
        }`}>
          {features.map((feature, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.1 * index + 0.3 }}
              whileHover={{ x: 5 }}
              className="flex items-center gap-4 group"
            >
              <motion.div
                whileHover={{ scale: 1.2, rotate: 360 }}
                transition={{ duration: 0.3 }}
                className={`w-7 h-7 rounded-full flex items-center justify-center ${
                  highlighted 
                    ? "bg-gradient-to-br from-white/20 to-white/10" 
                    : "bg-gradient-to-br from-emerald-100 to-emerald-50"
                }`}
              >
                <Check className={`w-4 h-4 ${
                  highlighted 
                    ? "text-white" 
                    : "text-emerald-600"
                }`} />
              </motion.div>
              <motion.span 
                whileHover={{ scale: 1.05 }}
                transition={{ duration: 0.2 }}
                className={`font-medium ${
                  highlighted 
                    ? "text-white/90" 
                    : "text-slate-700"
                }`}
              >
                {feature}
              </motion.span>
            </motion.div>
          ))}
        </div>

        {/* CTA Button */}
        <motion.button
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.5 }}
          whileHover={{ 
            scale: 1.05,
            boxShadow: "0 20px 40px -15px rgba(0,0,0,0.3)"
          }}
          whileTap={{ scale: 0.98 }}
          className={`w-full py-4 px-8 rounded-2xl font-bold text-lg transition-all duration-300 relative overflow-hidden group ${
            highlighted
              ? "bg-gradient-to-r from-white to-slate-100 text-slate-900 border-2 border-white/20"
              : "bg-gradient-to-r from-purple-600 via-pink-600 to-indigo-600 text-white border-2 border-purple-500/30"
          }`}
        >
          {/* Animated button background */}
          <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -skew-x-12 -translate-x-full group-hover:translate-x-full transition-transform duration-700" />

          <span className="relative z-10 flex items-center justify-center gap-2">
            {highlighted ? "Start Free Trial" : "Get Started"}
            <ArrowRight className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300 translate-x-2 group-hover:translate-x-0" />
          </span>
        </motion.button>
      </div>

      {/* Floating particles for highlighted cards */}
      {highlighted && (
        <>
          <motion.div
            animate={{
              y: [0, -20, 0],
              opacity: [0, 1, 0]
            }}
            transition={{
              duration: 3,
              repeat: Infinity,
              ease: "easeInOut",
              delay: 0
            }}
            className="absolute -top-2 -left-2 w-2 h-2 bg-amber-400 rounded-full"
          />
          <motion.div
            animate={{
              y: [0, -15, 0],
              opacity: [0, 1, 0]
            }}
            transition={{
              duration: 3,
              repeat: Infinity,
              ease: "easeInOut",
              delay: 1
            }}
            className="absolute -top-1 -right-3 w-1.5 h-1.5 bg-pink-400 rounded-full"
          />
          <motion.div
            animate={{
              y: [0, -25, 0],
              opacity: [0, 1, 0]
            }}
            transition={{
              duration: 3,
              repeat: Infinity,
              ease: "easeInOut",
              delay: 2
            }}
            className="absolute -bottom-2 left-4 w-2.5 h-2.5 bg-purple-400 rounded-full"
          />
        </>
      )}
    </motion.div>
  );
};

export default PricingCard;

