"use client";

import React, { useState } from "react";
import { Star, ShoppingCart, Heart } from "lucide-react";

interface ProductCardProps {
  title: string;
  price: string;
  image: string;
  rating?: number;
  originalPrice?: string;
  badge?: string;
  className?: string;
}

const ProductCard: React.FC<ProductCardProps> = ({
  title,
  price,
  image,
  rating = 0,
  originalPrice,
  badge,
  className = ""
}) => {
  const [isLiked, setIsLiked] = useState(false);

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }).map((_, i) => (
      <Star 
        key={i} 
        className={`w-4 h-4 ${
          i < Math.floor(rating) 
            ? "fill-yellow-400 text-yellow-400" 
            : i < rating 
            ? "fill-yellow-200 text-yellow-400" 
            : "text-slate-300"
        }`} 
      />
    ));
  };

  return (
    <div className={`bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-xl transition-all duration-300 group ${className}`}>
      <div className="relative">
        <div className="aspect-square overflow-hidden bg-slate-100">
          <img 
            src={image} 
            alt={title}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
          />
        </div>
        {badge && (
          <div className="absolute top-3 left-3 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded">
            {badge}
          </div>
        )}
        <button
          onClick={() => setIsLiked(!isLiked)}
          className="absolute top-3 right-3 w-8 h-8 bg-white/90 backdrop-blur-sm rounded-full flex items-center justify-center shadow-md hover:bg-white transition-colors"
        >
          <Heart className={`w-4 h-4 transition-colors ${
            isLiked ? "fill-red-500 text-red-500" : "text-slate-600"
          }`} />
        </button>
      </div>
      <div className="p-4">
        <h3 className="font-semibold text-slate-900 mb-2 line-clamp-2">{title}</h3>
        {rating > 0 && (
          <div className="flex items-center gap-1 mb-3">
            {renderStars(rating)}
            <span className="text-sm text-slate-600 ml-1">({rating})</span>
          </div>
        )}
        <div className="flex items-center gap-2 mb-4">
          <span className="text-xl font-bold text-slate-900">{price}</span>
          {originalPrice && (
            <span className="text-sm text-slate-500 line-through">{originalPrice}</span>
          )}
        </div>
        <button className="w-full bg-purple-600 text-white py-2 px-4 rounded-lg font-medium hover:bg-purple-700 transition-colors duration-200 flex items-center justify-center gap-2">
          <ShoppingCart className="w-4 h-4" />
          Add to Cart
        </button>
      </div>
    </div>
  );
};

export default ProductCard;

