"use client";

import React from "react";
import { TrendingUp, TrendingDown } from "lucide-react";

interface DashboardCardProps {
  title: string;
  value: string;
  chartData: number[];
  change?: string;
  isPositive?: boolean;
  className?: string;
}

const DashboardCard: React.FC<DashboardCardProps> = ({
  title,
  value,
  chartData,
  change,
  isPositive = true,
  className = ""
}) => {
  const max = Math.max(...chartData);
  const min = Math.min(...chartData);
  const range = max - min || 1;

  return (
    <div className={`bg-white rounded-xl shadow-md p-6 border border-slate-200 hover:shadow-lg transition-all duration-300 ${className}`}>
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-sm font-medium text-slate-600">{title}</h3>
        {change && (
          <div className={`flex items-center gap-1 text-xs font-medium ${
            isPositive ? "text-emerald-600" : "text-red-600"
          }`}>
            {isPositive ? (
              <TrendingUp className="w-3 h-3" />
            ) : (
              <TrendingDown className="w-3 h-3" />
            )}
            {change}
          </div>
        )}
      </div>
      <p className="text-2xl font-bold text-slate-900 mb-4">{value}</p>
      <div className="flex items-end gap-1 h-16">
        {chartData.map((value, index) => {
          const height = ((value - min) / range) * 100;
          return (
            <div
              key={index}
              className="flex-1 bg-gradient-to-t from-purple-500 to-purple-300 rounded-t-sm transition-all duration-500 hover:from-purple-600 hover:to-purple-400"
              style={{ height: `${Math.max(height, 10)}%` }}
            />
          );
        })}
      </div>
    </div>
  );
};

export default DashboardCard;

